const AWS = require('aws-sdk');

/**
 * Invoke another Lambda function using AWS SDK
 * @param {string} functionName - Target Lambda function name (from environment variable)
 * @param {object} payload - Payload to send (will be JSON serialized)
 * @param {string} invocationType - "RequestResponse" (sync) or "Event" (async). Default: "RequestResponse"
 * @returns {Promise<object|null>} - Parsed response payload for RequestResponse, null for Event
 */
const invokeLambda = async (functionName, payload, invocationType = 'RequestResponse') => {
    const lambda = new AWS.Lambda();
    const params = {
        FunctionName: functionName,
        InvocationType: invocationType,
        Payload: JSON.stringify(payload)
    };
    
    try {
        const result = await lambda.invoke(params).promise();
        if (invocationType === 'RequestResponse') {
            if (result.Payload) {
                return JSON.parse(result.Payload.toString());
            }
            return null;
        }
        return null;
    } catch (error) {
        console.error(`Error invoking Lambda ${functionName}:`, error);
        throw error;
    }
};

module.exports = {
    invokeLambda
};
